lesson.vulnerableCode:
app.post('/transfer', (req, res) => {
  const { amount, to } = req.body;
  // No token verification. If session exists, transfer executes.
  executeTransfer(req.session.userId, to, amount);
});

lesson.secureCode:
app.post('/transfer', verifyCsrfToken, (req, res) => {
  const { amount, to } = req.body;
  executeTransfer(req.session.userId, to, amount);
});
